record_types.code:
type Basic_Ack is record
   Delivery_Tag : Long_Long;
   Multiple : Boolean := False;
end record;

type Basic_Consume is record
   Reserved_1 : Short := 0;
   Queue : String_Access;
   Consumer_Tag : String_Access;
   No_Local : Boolean := False;
   No_Ack : Boolean := False;
   Exclusive : Boolean := False;
   No_Wait : Boolean := False;
   Arguments : Field_Table;
end record;

type Basic_Consume_Ok is record
   Consumer_Tag : String_Access;
end record;

type Basic_Deliver is record
   Consumer_Tag : String_Access;
   Delivery_Tag : Long_Long;
   Redelivered : Boolean;
   Exchange : String_Access;
   Routing_Key : String_Access;
end record;

type Basic_Publish is record
   Reserved_1 : Short := 0;
   Exchange : String_Access;
   Routing_Key : String_Access;
   Mandatory : Boolean := False;
   Immediate : Boolean := False;
end record;

type Channel_Close is record
   Reply_Code : Short;
   Reply_Text : String_Access;
   Class_Id : Short;
   Method_Id : Short;
end record;

type Channel_Open is record
   Reserved : String_Access;
end record;

type Channel_Open_Ok is record
   Reserved : String_Access;
end record;

type Connection_Close is record
   Reply_Code : Short;
   Reply_Text : String_Access;
   Class_Id : Short;
   Method_Id : Short;
end record;

type Connection_Open is record
   Virtual_Host : String_Access;
   Reserved_1 : String_Access;
   Reserved_2 : Boolean;
end record;

type Connection_Open_Ok is record
   Reserved : String_Access;
end record;

type Connection_Start is record
   Version_Major : Octet;
   Version_Minor : Octet;
   Server_Properties : Field_Table;
   Mechanisms : String_Access;
   Locales : String_Access;
end record;

type Connection_Start_Ok is record
   Client_Properties : Field_Table;
   Mechanism : String_Access;
   Response : String_Access;
   Locale : String_Access;
end record;

type Connection_Tune is record
   Channel_Max : Short;
   Frame_Max : Long;
   Heartbeat : Short;
end record;

type Connection_Tune_Ok is record
   Channel_Max : Short;
   Frame_Max : Long;
   Heartbeat : Short;
end record;

type Content_Header is record
   Class_Id : Short;
   Weight : Short := 0;
   Body_Size : Long_Long;
end record;

type Queue_Declare is record
   Reserved_1 : Short := 0;
   Queue : String_Access;
   Passive : Boolean := False;
   Durable : Boolean := False;
   Exclusive : Boolean := False;
   Auto_Delete : Boolean := False;
   No_Wait : Boolean := False;
   Arguments : Field_Table;
end record;

type Queue_Declare_Ok is record
   Queue : String_Access;
   Message_Count : Long;
   Consumer_Count : Long;
end record;

